# ocp_examples.py\n\n# =============================================================================\n# Open/Closed Principle (OCP) - Princípio Aberto/Fechado\n# =============================================================================\n\n# Definição: \"Entidades de software (classes, módulos, funções, etc.) devem ser abertas para extensão, mas fechadas para modificação.\"\n# Isso significa que você deve ser capaz de estender o comportamento de um módulo sem precisar modificar seu código-fonte.\n\n# -----------------------------------------------------------------------------\n# Exemplo RUIM: Violação do OCP\n# A classe `AreaCalculator` precisa ser modificada toda vez que uma nova forma é adicionada.\n# -----------------------------------------------------------------------------\n\nclass Rectangle:\n    def __init__(self, width, height):\n        self.width = width\n        self.height = height\n\nclass Circle:\n    def __init__(self, radius):\n        self.radius = radius\n\nclass AreaCalculatorBad:\n    def calculate_area(self, shapes):\n        total_area = 0\n        for shape in shapes:\n            if isinstance(shape, Rectangle):\n                total_area += shape.width * shape.height\n            elif isinstance(shape, Circle):\n                total_area += 3.14159 * shape.radius ** 2\n            # Problema: Se adicionarmos um novo tipo de forma (ex: Triangle),\n            # precisaremos modificar esta classe `AreaCalculatorBad`.\n            # Isso viola o OCP, pois a classe não está fechada para modificação.\n        return total_area\n\nprint(\"--- Exemplo RUIM (Violação do OCP) ---\")\nrectangle1 = Rectangle(10, 5)\ncircle1 = Circle(7)\n\ncalculator_bad = AreaCalculatorBad()\nprint(f\"Área total: {calculator_bad.calculate_area([rectangle1, circle1]):.2f}\")\n\n# Imagine que precisamos adicionar um Triângulo. Teríamos que editar AreaCalculatorBad.\nclass Triangle:\n    def __init__(self, base, height):\n        self.base = base\n        self.height = height\n\n# Para suportar Triangle, teríamos que modificar AreaCalculatorBad, adicionando um 'elif'\n# Isso é indesejável em um sistema grande e já testado.\nprint(\"-\" * 40)\n\n\n# -----------------------------------------------------------------------------\n# Exemplo BOM: Aplicação do OCP\n# Usando uma interface (classe abstrata) para permitir extensão sem modificação.\n# -----------------------------------------------------------------------------\n\nfrom abc import ABC, abstractmethod\n\nclass Shape(ABC):\n    @abstractmethod\n    def area(self):\n        pass\n\nclass RectangleGood(Shape):\n    def __init__(self, width, height):\n        self.width = width\n        self.height = height\n\    def area(self):\n        return self.width * self.height\n\nclass CircleGood(Shape):\n    def __init__(self, radius):\n        self.radius = radius\n\n    def area(self):\n        return 3.14159 * self.radius ** 2\n\nclass TriangleGood(Shape):\n    def __init__(self, base, height):\n        self.base = base\n        self.height = height\n\n    def area(self):\n        return 0.5 * self.base * self.height\n\nclass AreaCalculatorGood:\n    def calculate_area(self, shapes: list[Shape]):\n        total_area = 0\n        for shape in shapes:\n            total_area += shape.area()\n        return total_area\n\nprint(\"\\n--- Exemplo BOM (Aplicação do OCP) ---\")\nrectangle2 = RectangleGood(10, 5)\ncircle2 = CircleGood(7)\ntriangle1 = TriangleGood(10, 4)\n\ncalculator_good = AreaCalculatorGood()\nprint(f\"Área total: {calculator_good.calculate_area([rectangle2, circle2, triangle1]):.2f}\")\n\n# Benefícios:\n# - Se adicionarmos um novo tipo de forma (ex: Square), não precisamos modificar\n#   AreaCalculatorGood. Apenas criamos uma nova classe Square que herda de Shape\n#   e implementa o método 'area()'.\n# - A classe AreaCalculatorGood está 'fechada para modificação', mas 'aberta para extensão'.\nprint(\"-\" * 40)\n